// Clean text: remove ads, channel mentions, excess formatting
const item = $input.first().json;
const rawText = item.title || item.raw_text || '';

// Remove ad patterns
let cleaned = rawText
  .replace(/підписуйтесь|підпишись|subscribe|join|реклама|sponsored/gi, '')
  .replace(/@\w+/g, '')
  .replace(/👉[^\n]*/g, '')
  .replace(/\n{3,}/g, '\n\n')
  .trim();

// Truncate to reasonable title length
if (cleaned.length > 150) {
  cleaned = cleaned.substring(0, 150).trim() + '...';
}

return [{
  json: {
    ...item,
    title: cleaned || `Знахідка з AliExpress #${item.id}`,
    cleaned: true
  }
}];

// Generate affiliate link using AliExpress portals URL scheme
const item = $input.first().json;
const originalLink = item.original_link || '';
const trackingId = $env.AFFILIATE_TRACKING_ID || '';

let affiliateLink = originalLink;

// Method 1: If tracking ID is set, append affiliate params
if (trackingId && originalLink) {
  const separator = originalLink.includes('?') ? '&' : '?';
  affiliateLink = `${originalLink}${separator}aff_fcid=${trackingId}&aff_fsk=&aff_platform=portals-tool&sk=&aff_trace_key=&terminal_id=`;
}

// TODO: Method 2: Use AliExpress Affiliate API with App Key/Secret
// const apiUrl = 'https://api-sg.aliexpress.com/sync';
// Parameters: method=aliexpress.affiliate.link.generate, promotion_link_type=0, source_values=originalLink

return [{
  json: {
    ...item,
    affiliate_link: affiliateLink,
    original_link: originalLink
  }
}];

// Format the Telegram post
const item = $input.first().json;

const price = item.price ? `💰 $${Number(item.price).toFixed(2)}` : '💰 Ціну дивись за посиланням';
const title = item.title || 'Знахідка з AliExpress';
const link = item.affiliate_link || item.original_link || '';

const postText = `🔥 ${title}\n\n${price}\n🚚 Безкоштовна доставка\n\n🛒 Купити: ${link}\n\n📱 Більше знахідок: @Ekcoin`;

return [{
  json: {
    ...item,
    telegram_post: postText
  }
}];

// Add product to products.json for the website
const item = $input.first().json;
const fs = require('fs');
const path = 'E:/Shop_Na_Ali/site/data/products.json';

let data = { products: [] };
try {
  const raw = fs.readFileSync(path, 'utf-8');
  data = JSON.parse(raw);
} catch(e) {
  // File doesn't exist yet
}

const newProduct = {
  id: item.id,
  title: item.title,
  price: item.price || 0,
  category: 'other',
  badge: 'new',
  rating: 0,
  orders: 0,
  image: item.image_path ? `images/${item.image_filename}` : '',
  link: item.original_link,
  affiliate_link: item.affiliate_link || '',
  description: '',
  source_channel: item.source_channel || '',
  added_at: item.timestamp || new Date().toISOString()
};

// Add to beginning
data.products = data.products || [];
data.products.unshift(newProduct);

// Keep max 200 products
if (data.products.length > 200) {
  data.products = data.products.slice(0, 200);
}

fs.writeFileSync(path, JSON.stringify(data, null, 2), 'utf-8');

return [{ json: { success: true, product_id: item.id } }];
